<canvas id="eloChart"></canvas>
</div>

<div class="section">
<h2 style="margin-bottom:12px">⚔️ Match Log</h2>
<table><tr><th>Team A</th><th>Team B</th><th>Task</th><th>Winner</th><th>A Agg</th><th>B Agg</th></tr>
