            print(data)
    elif args.export == "html":
        html = _render_html(report)
        out = args.output or "resilience_report.html"
        with open(out, "w") as f:
            f.write(html)
        print(f"Interactive report written to {out}")
    else:
        _print_report(report)


if __name__ == "__main__":
